profile = Blueprint('profile', __name__)

@profile.route('/update', methods=['POST'])
def update_profile():
    data = request.json
    user_id = session['user_id']
    
    user = User.query.get(user_id)
    
    if 'email' in data:
        user.email = data['email']
        
